## 6. src/types.ts (Account Resolution)

Defines how accounts are resolved from config:

```typescript
import {
  DEFAULT_ACCOUNT_ID,
  normalizeAccountId,
  normalizeOptionalAccountId,
} from "openclaw/plugin-sdk/account-id";
import {
  listCombinedAccountIds,
  resolveListedDefaultAccountId,
} from "openclaw/plugin-sdk/account-resolution";
import { normalizeSecretInputString, type SecretInput } from "openclaw/plugin-sdk/secret-input";
import type { OpenClawConfig } from "../api.js";

export interface PulseboardAccountConfig {
  enabled?: boolean;
  name?: string;
  defaultAccount?: string;
  serverUrl?: string;
  apiKey?: SecretInput;
  workspace?: string;
  dmPolicy?: "pairing" | "allowlist" | "open" | "disabled";
  allowFrom?: Array<string | number>;
}

export interface ResolvedPulseboardAccount {
  accountId: string;
  name?: string;
  enabled: boolean;
  configured: boolean;
  serverUrl: string;
  apiKey: string;
  workspace: string;
  config: PulseboardAccountConfig;
}

export function listPulseboardAccountIds(cfg: OpenClawConfig): string[] {
  const pbCfg = (cfg.channels as Record<string, unknown> | undefined)?.pulseboard as
    | PulseboardAccountConfig
    | undefined;
  const apiKey = normalizeSecretInputString(pbCfg?.apiKey);
  return listCombinedAccountIds({
    configuredAccountIds: [],
    implicitAccountId: apiKey ? DEFAULT_ACCOUNT_ID : undefined,
  });
}

export function resolveDefaultPulseboardAccountId(cfg: OpenClawConfig): string {
  return resolveListedDefaultAccountId({
    accountIds: listPulseboardAccountIds(cfg),
    configuredDefaultAccountId: normalizeOptionalAccountId(
      ((cfg.channels as Record<string, unknown> | undefined)?.pulseboard as
        | PulseboardAccountConfig
        | undefined)?.defaultAccount,
    ),
  });
}

export function resolvePulseboardAccount(opts: {
  cfg: OpenClawConfig;
  accountId?: string | null;
}): ResolvedPulseboardAccount {
  const accountId = normalizeAccountId(
    opts.accountId ?? resolveDefaultPulseboardAccountId(opts.cfg),
  );
  const pbCfg = (opts.cfg.channels as Record<string, unknown> | undefined)?.pulseboard as
    | PulseboardAccountConfig
    | undefined;

  const baseEnabled = pbCfg?.enabled !== false;
  const apiKey = normalizeSecretInputString(pbCfg?.apiKey) ?? "";
  const configured = Boolean(apiKey);
  const serverUrl = pbCfg?.serverUrl ?? "https://api.pulseboard.io";
  const workspace = pbCfg?.workspace ?? "default";

  return {
    accountId,
    name: pbCfg?.name?.trim() || undefined,
    enabled: baseEnabled,
    configured,
    apiKey,
    serverUrl,
    workspace,
    config: {
      enabled: pbCfg?.enabled,
      name: pbCfg?.name,
      serverUrl: pbCfg?.serverUrl,
      apiKey: pbCfg?.apiKey,
      workspace: pbCfg?.workspace,
      dmPolicy: pbCfg?.dmPolicy,
      allowFrom: pbCfg?.allowFrom,
    },
  };
}
```

**Key patterns:**
- Separate interface types (`*AccountConfig` and `Resolved*Account`)
- Helper functions: `list*AccountIds()`, `resolveDefault*AccountId()`, `resolve*Account()`
- Account resolution handles multiple accounts (though MVP may use single)
- Secret inputs use SDK helpers to normalize

