129	function stripWhatsAppTargetPrefixes(value: string): string {
130	  let candidate = value.trim();
131	  for (;;) {
132	    const before = candidate;
133	    candidate = candidate.replace(/^whatsapp:/i, "").trim();
134	    if (candidate === before) {
135	      return candidate;
136	    }
137	  }
138	}
