140	function normalizeLocalWhatsAppTarget(value: string): string | null {
141	  const candidate = stripWhatsAppTargetPrefixes(value);
142	  if (!candidate) {
143	    return null;
144	  }
145	  if (candidate.toLowerCase().endsWith("@g.us")) {
146	    const localPart = candidate.slice(0, candidate.length - "@g.us".length);
147	    return /^[0-9]+(-[0-9]+)*$/.test(localPart) ? `${localPart}@g.us` : null;
148	  }
149	  const userMatch = candidate.match(WHATSAPP_USER_JID_RE);
150	  const lidMatch = candidate.match(WHATSAPP_LID_RE);
151	  const phone = userMatch?.[1] ?? lidMatch?.[1];
152	  if (phone) {
153	    const normalized = normalizeLocalE164(phone);
154	    return normalized.length > 1 ? normalized : null;
155	  }
156	  if (candidate.includes("@")) {
157	    return null;
158	  }
159	  const normalized = normalizeLocalE164(candidate);
160	  return normalized.length > 1 ? normalized : null;
