378	  ResolvedAccount,
379	  Config extends OpenClawConfig = OpenClawConfig,
380	>(params: {
381	  listAccountIds: (cfg: Config) => string[];
382	  resolveAccount: (cfg: Config, accountId?: string | null) => ResolvedAccount;
