import { DEFAULT_ACCOUNT_ID, normalizeAccountId } from "openclaw/plugin-sdk/account-id";
import { normalizeSecretInputString, type SecretInput } from "openclaw/plugin-sdk/secret-input";
import type { OpenClawConfig } from "../api.js";

/**
 * Per-board configuration overrides (optional; boards fall back to the root config).
 */
export type PulseBoardBoardConfig = {
  /** Require an @mention to trigger the bot in this board. Default: true. */
  requireMention?: boolean;
  /** Whether the bot is active in this board. */
  enabled?: boolean;
  /** Users allowed to trigger the bot in this board. */
  allowFrom?: Array<string | number>;
  /** Custom system prompt for this board. */
  systemPrompt?: string;
};

/**
 * Top-level channels.pulseboard configuration shape.
 * PulseBoard is a single-account channel; all keys live at the root.
 */
export type PulseBoardAccountConfig = {
  /** Optional display name for this account. */
  name?: string;
  /** Whether this channel is enabled. */
  enabled?: boolean;
  /** Base URL of the PulseBoard server, e.g. https://pb.example.com */
  serverUrl?: string;
  /** API key (or $file: / $env: reference) for authenticating with the server. */
  apiKey?: SecretInput;
  /** Username the bot signs in as. */
  botUsername?: string;
  /** DM access policy: pairing, allowlist, open, or disabled. */
  dmPolicy?: "pairing" | "allowlist" | "open" | "disabled";
  /** Users allowed to DM the bot (required when dmPolicy=allowlist or open). */
  allowFrom?: Array<string | number>;
  /** Boards (channels) the bot should join on connect. */
  boards?: string[];
  /** Per-board configuration overrides keyed by board name. */
  boardConfig?: Record<string, PulseBoardBoardConfig>;
  /** Maximum text chunk size for outbound messages (default: 4000). */
  textChunkLimit?: number;
};

export type PulseBoardConfig = PulseBoardAccountConfig;

/** Augmented OpenClawConfig that includes the pulseboard channel section. */
export type CoreConfig = OpenClawConfig & {
  channels?: OpenClawConfig["channels"] & {
    pulseboard?: PulseBoardConfig;
  };
};

/** Resolved, normalized account ready for use by the gateway and adapters. */
export interface ResolvedPulseBoardAccount {
  accountId: string;
  name?: string;
  enabled: boolean;
  configured: boolean;
  serverUrl: string;
  apiKey: string;
  botUsername: string;
  config: PulseBoardAccountConfig;
}

/** Returns the list of configured account IDs (always "default" for PulseBoard). */
export function listPulseBoardAccountIds(cfg: OpenClawConfig): string[] {
  const pbCfg = resolvePulseBoardRawConfig(cfg);
  const hasConfig = Boolean(pbCfg?.serverUrl?.trim() || pbCfg?.apiKey);
  return hasConfig ? [DEFAULT_ACCOUNT_ID] : [];
}

/** Returns the default account ID (always "default" for PulseBoard). */
export function resolveDefaultPulseBoardAccountId(_cfg: OpenClawConfig): string {
  return DEFAULT_ACCOUNT_ID;
}

/** Resolve and normalize the PulseBoard account from config. */
export function resolvePulseBoardAccount(opts: {
  cfg: OpenClawConfig;
  accountId?: string | null;
}): ResolvedPulseBoardAccount {
  const accountId = normalizeAccountId(opts.accountId ?? DEFAULT_ACCOUNT_ID);
  const pbCfg = resolvePulseBoardRawConfig(opts.cfg);

  const serverUrl = pbCfg?.serverUrl?.trim() ?? "";
  const apiKey = normalizeSecretInputString(pbCfg?.apiKey) ?? "";
  const botUsername = pbCfg?.botUsername?.trim() || "bot";
  const configured = Boolean(serverUrl && apiKey);

  return {
    accountId,
    name: pbCfg?.name?.trim() || undefined,
    enabled: pbCfg?.enabled !== false,
    configured,
    serverUrl,
    apiKey,
    botUsername,
    config: {
      name: pbCfg?.name,
      enabled: pbCfg?.enabled,
      serverUrl: pbCfg?.serverUrl,
      apiKey: pbCfg?.apiKey,
      botUsername: pbCfg?.botUsername,
      dmPolicy: pbCfg?.dmPolicy,
      allowFrom: pbCfg?.allowFrom,
      boards: pbCfg?.boards,
      boardConfig: pbCfg?.boardConfig,
      textChunkLimit: pbCfg?.textChunkLimit,
    },
  };
}

function resolvePulseBoardRawConfig(cfg: OpenClawConfig): PulseBoardAccountConfig | undefined {
  return (cfg.channels as Record<string, unknown> | undefined)
    ?.pulseboard as PulseBoardAccountConfig | undefined;
}

