import {
  AllowFromListSchema,
  buildChannelConfigSchema,
  DmPolicySchema,
  MarkdownConfigSchema,
} from "openclaw/plugin-sdk/channel-config-primitives";
import { buildSecretInputSchema } from "openclaw/plugin-sdk/secret-input";
import { z } from "openclaw/plugin-sdk/zod";

/**
 * Per-board override schema (boards fall back to the root config by default).
 */
export const PulseBoardBoardConfigSchema = z
  .object({
    requireMention: z.boolean().optional(),
    enabled: z.boolean().optional(),
    allowFrom: z.array(z.union([z.string(), z.number()])).optional(),
    systemPrompt: z.string().optional(),
  })
  .strict();

/**
 * Root channels.pulseboard schema.
 */
export const PulseBoardConfigSchema = z
  .object({
    /** Optional display name for this account. */
    name: z.string().optional(),
    /** Whether this channel is enabled. */
    enabled: z.boolean().optional(),
    /** Base URL of the PulseBoard server, e.g. https://pb.example.com */
    serverUrl: z.string().url().optional(),
    /** API key (or $file:/$env: reference) for authenticating with the server. */
    apiKey: buildSecretInputSchema().optional(),
    /** Username the bot signs in as on the PulseBoard server. */
    botUsername: z.string().optional(),
    /** DM access policy: pairing, allowlist, open, or disabled. */
    dmPolicy: DmPolicySchema.optional(),
    /** Users allowed to DM the bot. */
    allowFrom: AllowFromListSchema,
    /** Boards (channels) the bot should subscribe to on connect. */
    boards: z.array(z.string()).optional(),
    /** Per-board configuration overrides keyed by board name. */
    boardConfig: z.record(z.string(), PulseBoardBoardConfigSchema.optional()).optional(),
    /** Maximum characters per outbound text chunk (default: 4000). */
    textChunkLimit: z.number().int().min(1).max(8000).optional(),
    /** Markdown table rendering overrides. */
    markdown: MarkdownConfigSchema,
  })
  .strict();

export type PulseBoardConfigSchemaType = z.infer<typeof PulseBoardConfigSchema>;

/** JSON-schema-compatible config description for the Control UI. */
export const pulseBoardChannelConfigSchema = buildChannelConfigSchema(PulseBoardConfigSchema);

