import {
  buildChannelOutboundSessionRoute,
  stripChannelTargetPrefix,
  type ChannelOutboundSessionRouteParams,
} from "openclaw/plugin-sdk/core";

/**
 * Resolve the outbound session route for a PulseBoard target.
 *
 * Target formats:
 *   - Direct messages:  "<username>" or "pulseboard:<username>"
 *   - Board messages:   "#<board>" or "board:<board>" or "pulseboard:board:<board>"
 */
export function resolvePulseBoardOutboundSessionRoute(params: ChannelOutboundSessionRouteParams) {
  const stripped = stripChannelTargetPrefix(params.target, "pulseboard");
  if (!stripped) {
    return null;
  }

  // Detect board targets: #board or board:board
  if (stripped.startsWith("#") || stripped.startsWith("board:")) {
    const boardId = stripped.replace(/^(#|board:board:|board:)/, "").trim();
    if (!boardId) {
      return null;
    }
    return buildChannelOutboundSessionRoute({
      cfg: params.cfg,
      agentId: params.agentId,
      channel: "pulseboard",
      accountId: params.accountId,
      peer: { kind: "group", id: boardId },
      chatType: "group",
      from: `pulseboard:board:${boardId}`,
      to: `pulseboard:board:${boardId}`,
    });
  }

  // Direct message target
  const userId = stripped.trim();
  if (!userId) {
    return null;
  }
  return buildChannelOutboundSessionRoute({
    cfg: params.cfg,
    agentId: params.agentId,
    channel: "pulseboard",
    accountId: params.accountId,
    peer: { kind: "direct", id: userId },
    chatType: "direct",
    from: `pulseboard:${userId}`,
    to: `pulseboard:${userId}`,
  });
}

/** Return true if `input` looks like a PulseBoard target ID (not a full URL). */
export function looksLikePulseBoardTargetId(input: string): boolean {
  const trimmed = input.trim();
  return (
    trimmed.startsWith("#") ||
    /^board:/i.test(trimmed) ||
    /^pulseboard:/i.test(trimmed) ||
    // plain username: no spaces, no slashes, 1-64 chars
    (/^[A-Za-z0-9_.-]{1,64}$/.test(trimmed) && !trimmed.includes("."))
  );
}

/** Normalize a raw target string to a canonical PulseBoard target. */
export function normalizePulseBoardTarget(target: string): string {
  const trimmed = target.trim();
  // Board targets: strip leading # or board: prefix; keep lowercase
  if (trimmed.startsWith("#")) {
    return `#${trimmed.slice(1).trim().toLowerCase()}`;
  }
  if (/^board:/i.test(trimmed)) {
    return `#${trimmed.replace(/^board:/i, "").trim().toLowerCase()}`;
  }
  // Strip pulseboard: prefix and lowercase the rest
  return stripChannelTargetPrefix(trimmed, "pulseboard").toLowerCase();
}

