} from "../runtime-api.js";

// ---------------------------------------------------------------------------
// Active connection store
// ---------------------------------------------------------------------------

type PulseBoardConnection = {
  /** Send a DM or board post via the PulseBoard HTTP API. */
  send: (params: { type: "dm" | "board"; target: string; text: string }) => Promise<void>;
  /** Shut down the connection and release resources. */
  stop: () => void;
};

/** Active server connections keyed by accountId. */
const activeConnections = new Map<string, PulseBoardConnection>();

// ---------------------------------------------------------------------------
// Allow-from helpers
// ---------------------------------------------------------------------------

function normalizePulseBoardAllowEntry(entry: string): string | null {
  const trimmed = entry.trim().toLowerCase();
  if (!trimmed) {
    return null;
  }
  // Wildcards and plain usernames are valid allow entries.
  return trimmed === "*" ? "*" : trimmed.replace(/^pulseboard:/i, "");
}

function isPulseBoardSenderAllowed(senderId: string, allowFrom: string[]): boolean {
  const normalized = senderId.trim().toLowerCase();
  for (const entry of allowFrom) {
    if (entry === "*") {
      return true;
    }
    const normalizedEntry = normalizePulseBoardAllowEntry(entry);
    if (normalizedEntry && normalizedEntry === normalized) {
      return true;
    }
  }
  return false;
}

// ---------------------------------------------------------------------------
// Config + security adapters
// ---------------------------------------------------------------------------

const pulseBoardConfigAdapter = createTopLevelChannelConfigAdapter<ResolvedPulseBoardAccount>({
  sectionKey: "pulseboard",
  resolveAccount: (cfg) => resolvePulseBoardAccount({ cfg }),
  listAccountIds: listPulseBoardAccountIds,
  defaultAccountId: resolveDefaultPulseBoardAccountId,
  deleteMode: "clear-fields",
  clearBaseFields: ["name", "serverUrl", "apiKey", "botUsername", "dmPolicy", "allowFrom"],
  resolveAllowFrom: (account) => account.config.allowFrom,
  formatAllowFrom: (allowFrom) =>
    allowFrom
      .map((entry) => String(entry).trim().toLowerCase())
      .filter(Boolean)
      .map((entry) => (entry === "*" ? "*" : entry.replace(/^pulseboard:/i, "")))
      .filter(Boolean),
});

const resolvePulseBoardDmPolicy = createScopedDmSecurityResolver<ResolvedPulseBoardAccount>({
  channelKey: "pulseboard",
  resolvePolicy: (account) => account.config.dmPolicy,
  resolveAllowFrom: (account) => account.config.allowFrom,
  policyPathSuffix: "dmPolicy",
  defaultPolicy: "pairing",
  approveHint: formatPairingApproveHint("pulseboard"),
  normalizeEntry: (raw) => normalizePulseBoardAllowEntry(raw) ?? raw,
});

// ---------------------------------------------------------------------------
// Channel plugin definition
// ---------------------------------------------------------------------------

export const pulseBoardPlugin: ChannelPlugin<ResolvedPulseBoardAccount> = createChatChannelPlugin({
  base: {
    id: "pulseboard",
    meta: {
      id: "pulseboard",
      label: "PulseBoard",
      selectionLabel: "PulseBoard",
      docsPath: "/channels/pulseboard",
      docsLabel: "pulseboard",
      blurb: "Real-time bulletin board messaging (boards + DMs)",
      order: 70,
    },
    capabilities: {
      // Supports both direct messages and board (group) conversations.
      chatTypes: ["direct", "group"],
      media: false,
    },
    reload: { configPrefixes: ["channels.pulseboard"] },
    configSchema: buildChannelConfigSchema(pulseBoardChannelConfigSchema),
    setup: pulseBoardSetupAdapter,
    setupWizard: pulseBoardSetupWizard,
    config: {
      ...pulseBoardConfigAdapter,
      isConfigured: (account) => account.configured,
      describeAccount: (account) =>
        describeAccountSnapshot({
          account,
          configured: account.configured,
          extra: {
            serverUrl: account.serverUrl,
            botUsername: account.botUsername,
          },
        }),
    },
    messaging: {
      normalizeTarget: normalizePulseBoardTarget,
      targetResolver: {
        looksLikeId: looksLikePulseBoardTargetId,
        hint: "<username|#board>",
      },
      resolveOutboundSessionRoute: (params) => resolvePulseBoardOutboundSessionRoute(params),
    },
    status: {
      ...createComputedAccountStatusAdapter<ResolvedPulseBoardAccount>({
        defaultRuntime: createDefaultChannelRuntimeState(DEFAULT_ACCOUNT_ID),
        collectStatusIssues: (accounts) =>
          collectStatusIssuesFromLastError("pulseboard", accounts),
        buildChannelSummary: ({ snapshot }) =>
          buildPassiveChannelStatusSummary(snapshot, {
            serverUrl: (snapshot as { serverUrl?: string }).serverUrl ?? null,
            botUsername: (snapshot as { botUsername?: string }).botUsername ?? null,
            ...buildTrafficStatusSummary(snapshot),
          }),
        resolveAccountSnapshot: ({ account, runtime }) => ({
          accountId: account.accountId,
          name: account.name,
          enabled: account.enabled,
          configured: account.configured,
          extra: {
            serverUrl: account.serverUrl,
            botUsername: account.botUsername,
            ...buildTrafficStatusSummary(runtime),
          },
        }),
      }),
    },
    gateway: {
      startAccount: async (ctx) => {
        const account = ctx.account;

        if (!account.configured) {
          throw new Error(
            `PulseBoard is not configured for account "${account.accountId}" ` +
              `(need serverUrl and apiKey in channels.pulseboard).`,
          );
        }

        ctx.log?.info(
          `[${account.accountId}] starting PulseBoard provider (${account.serverUrl})`,
        );
        ctx.setStatus({ serverUrl: account.serverUrl, botUsername: account.botUsername });

        const runtime = getPulseBoardRuntime();
        const pairing = createChannelPairingController({
          core: runtime,
          channel: "pulseboard",
          accountId: account.accountId,
        });

        // Shared access resolver for the DM inbound pipeline.
        const resolveInboundAccess = async (senderId: string, rawBody: string) =>
          resolveInboundDirectDmAccessWithRuntime({
            cfg: ctx.cfg,
            channel: "pulseboard",
            accountId: account.accountId,
            dmPolicy: account.config.dmPolicy ?? "pairing",
            allowFrom: account.config.allowFrom,
            senderId,
            rawBody,
            isSenderAllowed: isPulseBoardSenderAllowed,
            runtime: {
              shouldComputeCommandAuthorized:
                runtime.channel.commands.shouldComputeCommandAuthorized,
              resolveCommandAuthorizedFromAuthorizers:
                runtime.channel.commands.resolveCommandAuthorizedFromAuthorizers,
            },
          });

        // Pre-crypto gate: runs before decrypting/parsing the message body.
        const authorizeDmSender = createPreCryptoDirectDmAuthorizer({
          resolveAccess: async (senderId) => resolveInboundAccess(senderId, ""),
          issuePairingChallenge: async ({ senderId, reply }) => {
            await pairing.issueChallenge({
              senderId,
              senderIdLine: `PulseBoard username: ${senderId}`,
              sendPairingReply: reply,
              onCreated: () => {
                ctx.log?.debug?.(
                  `[${account.accountId}] PulseBoard pairing request from ${senderId}`,
                );
              },
              onReplyError: (err) => {
                ctx.log?.warn?.(
                  `[${account.accountId}] pairing reply failed for ${senderId}: ${String(err)}`,
                );
              },
            });
          },
          onBlocked: ({ senderId, reason }) => {
            ctx.log?.debug?.(
              `[${account.accountId}] blocked PulseBoard sender ${senderId} (${reason})`,
            );
          },
        });

        // -----------------------------------------------------------------
        // Inbound DM handler
        // -----------------------------------------------------------------
        const handleDm = async (msg: {
          senderId: string;
          text: string;
          messageId: string;
          timestamp: number;
          reply: (text: string) => Promise<void>;
        }) => {
          // Pre-flight authorization (pairing challenge / allowlist check).
          const authResult = await authorizeDmSender({
            senderId: msg.senderId,
            reply: msg.reply,
          });
          if (authResult !== "allow") {
            return;
          }

          // Full access check with command-auth resolution.
          const access = await resolveInboundAccess(msg.senderId, msg.text);
          if (access.access.decision !== "allow") {
            ctx.log?.warn?.(
              `[${account.accountId}] dropping DM from ${msg.senderId} (${access.access.reason})`,
            );
            return;
          }

          await dispatchInboundDirectDmWithRuntime({
            cfg: ctx.cfg,
            runtime,
            channel: "pulseboard",
            channelLabel: "PulseBoard",
            accountId: account.accountId,
            peer: { kind: "direct", id: msg.senderId },
            senderId: msg.senderId,
            senderAddress: `pulseboard:${msg.senderId}`,
            recipientAddress: `pulseboard:${account.botUsername}`,
            conversationLabel: msg.senderId,
            rawBody: msg.text,
            messageId: msg.messageId,
            timestamp: msg.timestamp,
            commandAuthorized: access.commandAuthorized,
            deliver: async (payload) => {
              const outboundText =
                payload && typeof payload === "object" && "text" in payload
                  ? String((payload as { text?: string }).text ?? "")
                  : "";
              if (!outboundText.trim()) {
                return;
              }
              const tableMode = runtime.channel.text.resolveMarkdownTableMode({
                cfg: ctx.cfg,
                channel: "pulseboard",
                accountId: account.accountId,
              });
              await msg.reply(runtime.channel.text.convertMarkdownTables(outboundText, tableMode));
            },
            onRecordError: (err) => {
              ctx.log?.error?.(
                `[${account.accountId}] failed recording PulseBoard DM session: ${String(err)}`,
              );
            },
            onDispatchError: (err, info) => {
              ctx.log?.error?.(
                `[${account.accountId}] PulseBoard DM ${info.kind} reply failed: ${String(err)}`,
              );
            },
          });
        };

        // -----------------------------------------------------------------
        // Inbound board (group) message handler
        //
        // Board messages are dispatched as group conversations using the
        // runtime's routing and reply pipeline directly. This mirrors the
        // pattern used by dispatchInboundDirectDmWithRuntime but with
        // peer.kind = "group" so the session key reflects a board context.
        // A full generic helper (e.g. dispatchInboundGroupWithRuntime) would
        // live in openclaw/plugin-sdk/pulseboard once this plugin graduates
        // to a full bundled SDK facade.
        // -----------------------------------------------------------------
        const handleBoardMessage = async (msg: {
          boardId: string;
          senderId: string;
          text: string;
          messageId: string;
          timestamp: number;
          reply: (text: string) => Promise<void>;
        }) => {
          const route = runtime.channel.routing.resolveAgentRoute({
            cfg: ctx.cfg,
            channel: "pulseboard",
            accountId: account.accountId,
            peer: { kind: "group", id: msg.boardId },
          });

          const recipientAddress = `pulseboard:board:${msg.boardId}`;
          const senderAddress = `pulseboard:${msg.senderId}`;

          const ctxPayload = runtime.channel.reply.finalizeInboundContext({
            Body: msg.text,
            BodyForAgent: msg.text,
            RawBody: msg.text,
            CommandBody: msg.text,
            From: senderAddress,
            To: recipientAddress,
            SessionKey: route.sessionKey,
            AccountId: route.accountId ?? account.accountId,
            ChatType: "group",
            ConversationLabel: `#${msg.boardId}`,
            SenderId: msg.senderId,
            Provider: "pulseboard",
            Surface: "pulseboard",
            MessageSid: msg.messageId,
            MessageSidFull: msg.messageId,
            Timestamp: msg.timestamp,
            CommandAuthorized: undefined,
            OriginatingChannel: "pulseboard",
            OriginatingTo: recipientAddress,
          });

          await runtime.channel.reply.dispatchReplyWithBufferedBlockDispatcher({
            agentId: route.agentId,
            sessionKey: route.sessionKey,
            ctxPayload,
            deliver: async (payload) => {
              const outboundText =
                payload && typeof payload === "object" && "text" in payload
                  ? String((payload as { text?: string }).text ?? "")
                  : "";
              if (!outboundText.trim()) {
                return;
              }
              const tableMode = runtime.channel.text.resolveMarkdownTableMode({
                cfg: ctx.cfg,
                channel: "pulseboard",
                accountId: account.accountId,
              });
              await msg.reply(runtime.channel.text.convertMarkdownTables(outboundText, tableMode));
            },
          });
        };

        // -----------------------------------------------------------------
        // Outbound send helper (used by sendText below and the stop handler)
        // In a real implementation this would POST to the PulseBoard HTTP API
        // using account.serverUrl and account.apiKey.
        // -----------------------------------------------------------------
        let stopped = false;
        const send = async (params: {
          type: "dm" | "board";
          target: string;
          text: string;
        }): Promise<void> => {
          if (stopped) {
            throw new Error(
              `PulseBoard connection already stopped for account ${account.accountId}`,
            );
          }
          const endpoint =
            params.type === "board"
              ? `${account.serverUrl}/api/boards/${encodeURIComponent(params.target)}/messages`
              : `${account.serverUrl}/api/dm/${encodeURIComponent(params.target)}`;
          ctx.log?.debug?.(
            `[${account.accountId}] sending ${params.type} to ${params.target} ` +
              `(${endpoint}): ${params.text.slice(0, 60)}...`,
          );
          // Production code would: await fetch(endpoint, { method: "POST", ... })
        };

        // Register the connection so the outbound adapter can reach it.
        activeConnections.set(account.accountId, { send, stop: () => { stopped = true; } });

        // Subscribe to configured boards.
        const boards = account.config.boards ?? [];
        if (boards.length > 0) {
          ctx.log?.info(
            `[${account.accountId}] subscribing to boards: ${boards.join(", ")}`,
          );
        }

        ctx.log?.info(
          `[${account.accountId}] PulseBoard provider started ` +
            `(botUsername=${account.botUsername}, boards=${boards.length})`,
        );

        // Return cleanup function called by the gateway lifecycle when the
        // account is stopped (e.g. config reload, gateway shutdown).
        return {
          stop: () => {
            stopped = true;
            activeConnections.delete(account.accountId);
            ctx.log?.info(`[${account.accountId}] PulseBoard provider stopped`);
          },
          // Expose inbound handlers for use by a real WebSocket/polling client.
          // These are not part of the official gateway contract but are exported
          // here so integration code can wire up a live PulseBoard connection.
          _handleDm: handleDm,
          _handleBoardMessage: handleBoardMessage,
        };
      },
    },
  },

  // -------------------------------------------------------------------------
  // Pairing: when a new sender DMs the bot and dmPolicy=pairing, send them a
  // challenge they must acknowledge via `openclaw pairing approve pulseboard`.
  // -------------------------------------------------------------------------
  pairing: {
    text: {
      idLabel: "pulseBoardUsername",
      message: "Your pairing request has been approved. You can now send messages to the bot.",
      normalizeAllowEntry: (entry) => normalizePulseBoardAllowEntry(entry) ?? entry,
      notify: async ({ id, message, accountId }) => {
        const aid = accountId ?? DEFAULT_ACCOUNT_ID;
        const conn = activeConnections.get(aid);
        if (conn) {
          await conn.send({ type: "dm", target: id, text: message });
        }
      },
    },
  },

  // -------------------------------------------------------------------------
  // Security: account-scoped DM policy resolver.
  // -------------------------------------------------------------------------
  security: {
    resolveDmPolicy: resolvePulseBoardDmPolicy,
  },

  // -------------------------------------------------------------------------
  // Outbound: deliver text replies to DMs and boards.
  // -------------------------------------------------------------------------
  outbound: {
    deliveryMode: "direct",
    textChunkLimit: PULSEBOARD_DEFAULT_TEXT_CHUNK_LIMIT,
    sendText: async ({ cfg, to, text, accountId }) => {
      const core = getPulseBoardRuntime();
      const aid = accountId ?? DEFAULT_ACCOUNT_ID;
      const conn = activeConnections.get(aid);
      if (!conn) {
        throw new Error(`PulseBoard connection not running for account ${aid}`);
      }

      const tableMode = core.channel.text.resolveMarkdownTableMode({
        cfg,
        channel: "pulseboard",
        accountId: aid,
      });
      const message = core.channel.text.convertMarkdownTables(text ?? "", tableMode);

      // Route to board or DM based on target prefix.
      const isBoardTarget = to.startsWith("#") || /^board:/i.test(to);
      const normalizedTarget = isBoardTarget
        ? to.replace(/^(#|board:)/i, "").toLowerCase()
        : to.replace(/^pulseboard:/i, "").toLowerCase();

      await conn.send({ type: isBoardTarget ? "board" : "dm", target: normalizedTarget, text: message });

      return attachChannelToResult("pulseboard", {
        to: normalizedTarget,
        messageId: `pb-${Date.now()}`,
      });
    },
  },
});

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

/** Default maximum characters per outbound text chunk (matches PulseBoard server limit). */
const PULSEBOARD_DEFAULT_TEXT_CHUNK_LIMIT = 4000;

// ---------------------------------------------------------------------------
// Module-level helpers exposed for testing and status reporting
// ---------------------------------------------------------------------------

/** Return the active connection handle for a given account, if any. */
export function getPulseBoardConnection(
  accountId: string = DEFAULT_ACCOUNT_ID,
): PulseBoardConnection | undefined {
  return activeConnections.get(accountId);
}

/** Return a snapshot of all active PulseBoard connections. */
export function getActivePulseBoardConnections(): Map<string, PulseBoardConnection> {
  return new Map(activeConnections);
}

// Re-export runtime type so that tests and the index entry can reference it
// without importing the runtime store directly.
export type { PluginRuntime } from "../runtime-api.js";
export type { OpenClawConfig };

