// ---------------------------------------------------------------------------
// Allow-from helpers
// ---------------------------------------------------------------------------

function normalizePulseBoardAllowEntry(entry: string): string | null {
  const trimmed = entry.trim().toLowerCase();
  if (!trimmed) {
    return null;
  }
  // Wildcards and plain usernames are valid allow entries.
  return trimmed === "*" ? "*" : trimmed.replace(/^pulseboard:/i, "");
}

function isPulseBoardSenderAllowed(senderId: string, allowFrom: string[]): boolean {
  const normalized = senderId.trim().toLowerCase();
  for (const entry of allowFrom) {
    if (entry === "*") {
      return true;
    }
    const normalizedEntry = normalizePulseBoardAllowEntry(entry);
    if (normalizedEntry && normalizedEntry === normalized) {
      return true;
    }
  }
  return false;
}

