  // -------------------------------------------------------------------------
  security: {
    resolveDmPolicy: resolvePulseBoardDmPolicy,
  },

  // -------------------------------------------------------------------------
  // Outbound: deliver text replies to DMs and boards.
  // -------------------------------------------------------------------------
  outbound: {
    deliveryMode: "direct",
    textChunkLimit: PULSEBOARD_DEFAULT_TEXT_CHUNK_LIMIT,
    sendText: async ({ cfg, to, text, accountId }) => {
      const core = getPulseBoardRuntime();
      const aid = accountId ?? DEFAULT_ACCOUNT_ID;
      const conn = activeConnections.get(aid);
      if (!conn) {
        throw new Error(`PulseBoard connection not running for account ${aid}`);
      }

      const tableMode = core.channel.text.resolveMarkdownTableMode({
        cfg,
        channel: "pulseboard",
        accountId: aid,
      });
      const message = core.channel.text.convertMarkdownTables(text ?? "", tableMode);

      // Route to board or DM based on target prefix.
      const isBoardTarget = to.startsWith("#") || /^board:/i.test(to);
      const normalizedTarget = isBoardTarget
        ? to.replace(/^(#|board:)/i, "").toLowerCase()
        : to.replace(/^pulseboard:/i, "").toLowerCase();

      await conn.send({ type: isBoardTarget ? "board" : "dm", target: normalizedTarget, text: message });

      return attachChannelToResult("pulseboard", {
        to: normalizedTarget,
        messageId: `pb-${Date.now()}`,
      });
    },
  },
});

// ---------------------------------------------------------------------------
// Module-level helpers exposed for testing and status reporting
// ---------------------------------------------------------------------------

/** Return the active connection handle for a given account, if any. */
export function getPulseBoardConnection(
  accountId: string = DEFAULT_ACCOUNT_ID,
): PulseBoardConnection | undefined {
  return activeConnections.get(accountId);
}

/** Return a snapshot of all active PulseBoard connections. */
export function getActivePulseBoardConnections(): Map<string, PulseBoardConnection> {
  return new Map(activeConnections);
}

// Re-export runtime type so that tests and the index entry can reference it
// without importing the runtime store directly.
export type { PluginRuntime } from "../runtime-api.js";
export type { OpenClawConfig };

