import type { ChannelPlugin } from "openclaw/plugin-sdk/core";
import { defineChannelPluginEntry } from "openclaw/plugin-sdk/core";
import { pulseBoardPlugin } from "./src/channel.js";
import { setPulseBoardRuntime } from "./src/runtime.js";

export { pulseBoardPlugin } from "./src/channel.js";
export { setPulseBoardRuntime } from "./src/runtime.js";

export default defineChannelPluginEntry({
  id: "pulseboard",
  name: "PulseBoard",
  description: "PulseBoard real-time bulletin board channel plugin",
  plugin: pulseBoardPlugin as ChannelPlugin,
  setRuntime: setPulseBoardRuntime,
});

// Public API surface for the bundled PulseBoard extension.
// Core or other plugins may import from this barrel to access
// account resolution helpers and shared types.
export type { OpenClawConfig } from "openclaw/plugin-sdk/core";
export type {
  CoreConfig as PulseBoardCoreConfig,
  PulseBoardAccountConfig,
  PulseBoardBoardConfig,
  PulseBoardConfig,
  ResolvedPulseBoardAccount,
} from "./src/types.js";
export {
  listPulseBoardAccountIds,
  resolveDefaultPulseBoardAccountId,
  resolvePulseBoardAccount,
} from "./src/types.js";

// Private runtime barrel for the bundled PulseBoard extension.
// Keep this barrel thin and aligned with the local extension surface.
//
// Note: when a dedicated openclaw/plugin-sdk/pulseboard facade is added
// (promoted to a full bundled plugin), replace these direct subpath imports
// with a single `export * from "openclaw/plugin-sdk/pulseboard"`.

export { buildChannelConfigSchema } from "openclaw/plugin-sdk/channel-config-primitives";
export {
  DEFAULT_ACCOUNT_ID,
  formatPairingApproveHint,
  type ChannelPlugin,
  type OpenClawConfig,
} from "openclaw/plugin-sdk/core";
export {
  createPreCryptoDirectDmAuthorizer,
  dispatchInboundDirectDmWithRuntime,
  resolveInboundDirectDmAccessWithRuntime,
} from "openclaw/plugin-sdk/direct-dm";
export type { PluginRuntime } from "openclaw/plugin-sdk/runtime-store";
export {
  collectStatusIssuesFromLastError,
  createDefaultChannelRuntimeState,
} from "openclaw/plugin-sdk/status-helpers";

