2	import { normalizeSecretInputString, type SecretInput } from "openclaw/plugin-sdk/secret-input";
3	import type { OpenClawConfig } from "../api.js";
4	
5	/**
6	 * Per-board configuration overrides (optional; boards fall back to the root config).
7	 */
8	export type PulseBoardBoardConfig = {
9	  /** Require an @mention to trigger the bot in this board. Default: true. */
10	  requireMention?: boolean;
11	  /** Whether the bot is active in this board. */
12	  enabled?: boolean;
13	  /** Users allowed to trigger the bot in this board. */
14	  allowFrom?: Array<string | number>;
15	  /** Custom system prompt for this board. */
16	  systemPrompt?: string;
17	};
18	
19	/**
20	 * Top-level channels.pulseboard configuration shape.
21	 * PulseBoard is a single-account channel; all keys live at the root.
22	 */
23	export type PulseBoardAccountConfig = {
24	  /** Optional display name for this account. */
25	  name?: string;
26	  /** Whether this channel is enabled. */
27	  enabled?: boolean;
28	  /** Base URL of the PulseBoard server, e.g. https://pb.example.com */
29	  serverUrl?: string;
30	  /** API key (or $file: / $env: reference) for authenticating with the server. */
31	  apiKey?: SecretInput;
32	  /** Username the bot signs in as. */
33	  botUsername?: string;
34	  /** DM access policy: pairing, allowlist, open, or disabled. */
35	  dmPolicy?: "pairing" | "allowlist" | "open" | "disabled";
36	  /** Users allowed to DM the bot (required when dmPolicy=allowlist or open). */
37	  allowFrom?: Array<string | number>;
38	  /** Boards (channels) the bot should join on connect. */
39	  boards?: string[];
40	  /** Per-board configuration overrides keyed by board name. */
41	  boardConfig?: Record<string, PulseBoardBoardConfig>;
42	  /** Maximum text chunk size for outbound messages (default: 4000). */
43	  textChunkLimit?: number;
44	};
45	
46	export type PulseBoardConfig = PulseBoardAccountConfig;
47	
48	/** Augmented OpenClawConfig that includes the pulseboard channel section. */
49	export type CoreConfig = OpenClawConfig & {
50	  channels?: OpenClawConfig["channels"] & {
51	    pulseboard?: PulseBoardConfig;
52	  };
53	};
54	
55	/** Resolved, normalized account ready for use by the gateway and adapters. */
56	export interface ResolvedPulseBoardAccount {
57	  accountId: string;
58	  name?: string;
59	  enabled: boolean;
60	  configured: boolean;
61	  serverUrl: string;
62	  apiKey: string;
63	  botUsername: string;
64	  config: PulseBoardAccountConfig;
